css:
.loader {color: var(--loader-color, #f97316);
  --loader-secondary-color: #facc15;
  --loader-bg: #ffffff;
  display: inline-grid;
  width: 40px;
  aspect-ratio: 1;
}.loader:before,.loader:after {content:"";
  grid-area: 1/1;
  border-radius: 50%;
  background: repeating-conic-gradient(var(--loader-color, #f97316) 0 60deg,var(--loader-secondary-color, #facc15) 0 120deg);
}.loader:before {transform: rotate(0turn) translate(100%) rotate(0turn);
  animation: l5 4s linear infinite;
}.loader:after {padding: 20%;
  mask: conic-gradient(currentColor 0 0) content-box exclude,conic-gradient(currentColor 0 0);
  scale: -1 1;
}@keyframes l5 {to{transform: rotate(1turn) translate(100%) rotate(1turn)}}
